%% 
-module(f18_rom).

-compile(export_all).

-define(ROM_VERSION, "1.2").

unique_roms() ->
    enumerate_roms(rom_list(),[],#{}).

enumerate_roms([{Node,Rom}|List],Acc,RomMap) ->
    RomType = get_node_rom_type(Node),
    case maps:find(RomType, RomMap) of
	{ok,_} ->
	    enumerate_roms(List, [{Node,RomType}|Acc], RomMap);
	error ->
	    enumerate_roms(List, [{Node,RomType}|Acc], 
			   RomMap#{ RomType => Rom })
    end;
enumerate_roms([],Acc,RomMap) ->
    {Acc, RomMap}.

crc32(Rom) ->
    erlang:crc32(<< <<V:32>> || V <- Rom>>).

%% format roms as C arrays
format_roms() ->
    {ok, Fd} = file:open("f18_rom.c", [write]),
    try format_roms(Fd) of
	Res -> Res
    after
	file:close(Fd)
    end.

format_roms(Fd) ->
    io:format(Fd, "// Generated with f18_rom:format_roms().\n", []),
    io:format(Fd, "#include \"f18.h\"\n\n", []),
    io:format(Fd, "#include \"f18_strings.h\"  // only once!!\n", []),

    {RomList, RomMap} = unique_roms(),
    lists:foreach(
      fun({RomType,ROM}) ->
	      format_rom_symbols(Fd, RomType),
	      io:format(Fd, "static const uint18_t ~s_rom[] = ~w;\n\n", [RomType,ROM])
      end, maps:to_list(RomMap)),

    io:format(Fd, "const f18_rom_t RomMap[] = {\n", []),
    lists:foreach(
      fun({RomType,ROM}) ->
	      io:format(Fd, " [~s] = {~s, \"~s\", \"~s\", ~s_rom, ~w},\n", 
			[RomType, RomType, 
			 RomType, ?ROM_VERSION,
			 RomType, tuple_size(ROM)])
      end, maps:to_list(RomMap)),
    io:format(Fd, "};\n\n", []),

    io:format(Fd, "const f18_rom_type_t RomTypeMap[8][18] = {\n", []),
    lists:foreach(
      fun(I) ->
	      io:format(Fd, "  {", []),
	      lists:foreach(
		fun(J) ->
			Index = I*100+J,
			{_,RomType} = lists:keyfind(Index, 1, RomList),
			io:format(Fd ,"~s,", [RomType])
		end, lists:seq(0,17)),
	      io:format(Fd, "},\n", [])
      end, lists:seq(0,7)),
    io:format(Fd, "};\n\n", []),
    io:format(Fd, "const f18_symbol_t* SymMap[8][18] = {\n", []),
    lists:foreach(
      fun(I) ->
	      io:format(Fd, "  {", []),
	      lists:foreach(
		fun(J) ->
			Index = I*100+J,
			{_,RomType} = lists:keyfind(Index, 1, RomList),
			io:format(Fd, "~s_sym,", [RomType])
		end, lists:seq(0,17)),
	      io:format(Fd, "},\n", [])
      end, lists:seq(0,7)),
    io:format(Fd, "};\n", []).
    
format_rom_symbols(Fd, RomType) ->
    SymMap = maps:get(RomType, rom_symbols()),
    io:format(Fd, "const f18_symbol_t ~s_sym[] = {\n", [RomType]),
    lists:foreach(
      fun({Sym, Addr}) ->
	      io:format(Fd, " { 0x~3.16.0b, SYMSTR(~s)},\n", 
			[Addr,f18_strings:encode_chars(Sym)])
      end, lists:keysort(2, maps:to_list(SymMap))),
    io:format(Fd, " { 0x3ff, (char*) 0},\n", []),
    io:format(Fd, "};\n", []).

get_node_rom_type(Node) when is_integer(Node), Node >= 000, Node =< 717 ->
    maps:get(Node, node_rom_types(), basic).
	      
